+function scorePWM(sequence: string, pwm: Record<string, number[]>): number {
+  let score = 0;
+  for (let i = 0; i < sequence.length && i < pwm['A'].length; i++) {
+    const base = sequence[i].toUpperCase();
+    score += Math.log2((pwm[base]?.[i] ?? 0.25) / 0.25);
+  }
+  return score;
+}
