+interface DatedSequence {
+  id: string;
+  sequence: string;
+  collectionDate: Date;
+}
+
+interface TreeNode {
+  id: string;
+  branchLength: number;
+  date?: number;
+  children: TreeNode[];
+  dnds?: number;
+}
